class Solution:
    def lexicographicallySmallestArray(self, nums: List[int], limit: int) -> List[int]:
        indices = {num: i for i, num in enumerate(nums)}
        nums_sorted = sorted(nums)
        n = len(nums)
        result = [0] * n
        i = 0
        while i < n:
            j = i
            while j < n and nums_sorted[j] - nums_sorted[i] <= limit:
                j += 1
            for k in range(i, j):
                result[indices[nums_sorted[k]]] = nums_sorted[k]
            i = j
        return result
